import{_ as e,o as a,c as t,a as i}from"./app.09e3ab02.js";const u=JSON.parse('{"title":"TheOrangeWizard v. ShinigamiFTW, Dec 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/theorangewizard_v_shinigamiftw_dec_2017.md","lastUpdated":1666028275000}'),n={name:"government/court-cases-precedents/theorangewizard_v_shinigamiftw_dec_2017.md"},r=i('<h1 id="theorangewizard-v-shinigamiftw-dec-2017" tabindex="-1">TheOrangeWizard v. ShinigamiFTW, Dec 2017 <a class="header-anchor" href="#theorangewizard-v-shinigamiftw-dec-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: WackyAki</p><p><strong>Date</strong>: 2nd December 2017</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><p>ShinigamiFTW with breaking and entering.</p><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>Not guilty by reason of necessity.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>Orange alleges that ShinigamiFTW broke into the Xp room by breaking the blocks next to the doors.</p></li><li><p>ShinigamiFTW alleges that he had been let in by Modshot who then went AFK and he needed to escape.</p></li><li><p>ShinigamiFTW apologizes.</p></li><li><p>Aki asks Orange what he would have done in Shini&#39;s shoes.</p></li><li><p>Orange says he doesn&#39;t know.</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><blockquote><p>Shinigami, you didn\u2019t deny the fact that you broke the wall, and orange you didn\u2019t unfairly blame him. In interest in setting precedent, I\u2019ll ask shinigami or, due to the fact that they offered for another citizen, to repair damage not overtly compromising the security of yoahtl, devFTW to pay back the damages in reenforcement costs: 2 stone blocks. I also ask that, in interest of setting precident, that this stone not come from a government chest. Finally, I have come to this conclusion due to the fact that damages were done and neither party are irresponsible in their claims. Finally, this is not a reparation eased by previous contributons nor is it worsened because of the short history of belief shinigami is with an enemy force</p></blockquote>',11),o=[r];function s(h,d,c,l,g,p){return a(),t("div",null,o)}const _=e(n,[["render",s]]);export{u as __pageData,_ as default};
